// Resolves when ALL succeed
await Promise.all([p1, p2, p3])

// Resolves when FIRST succeeds
await Promise.any([p1, p2, p3])

// Resolves when ALL settle (success or fail)
await Promise.allSettled([p1, p2, p3])

// Resolves when FIRST settles
await Promise.race([p1, p2, p3])
